import React, { useEffect, useState } from "react";
import axios from "axios";
import { XMarkIcon } from "@heroicons/react/24/solid";
import Swal from "sweetalert2";

/* =========================
   SweetAlert Toast Setup
========================= */
const Toast = Swal.mixin({
  toast: true,
  position: "top-end",
  showConfirmButton: false,
  timer: 2000,
  timerProgressBar: true,
});

/* =========================
   Floating Input
========================= */
const FloatingLabelInput = ({
  name,
  type = "text",
  label,
  value,
  onChange,
  required,
  disabled,
}) => (
  <div className="relative w-full">
    <input
      type={type}
      name={name}
      id={name}
      value={value}
      onChange={onChange}
      placeholder=" "
      required={required}
      disabled={disabled}
      className={`peer w-full px-4 py-3 rounded-lg border text-black placeholder-transparent focus:outline-none focus:ring-2 focus:ring-indigo-600 transition-all ${
        disabled ? "bg-gray-200 cursor-not-allowed" : "bg-white border-gray-300"
      }`}
    />
    <label
      htmlFor={name}
      className={`absolute left-4 text-gray-500 transition-all
        peer-placeholder-shown:top-3.5 peer-placeholder-shown:text-base
        peer-focus:top-1 peer-focus:text-sm peer-focus:text-indigo-600
        ${value ? "top-1 text-sm text-indigo-600" : "top-3.5"}`}
    >
      {label} {required && <span className="text-red-500">*</span>}
    </label>
  </div>
);

export default function UserAdm() {
  const BASE_URL = "http://localhost:8086/user";

  const [users, setUsers] = useState([]);
  const [filteredUsers, setFilteredUsers] = useState([]);
  const [search, setSearch] = useState("");
  const [loading, setLoading] = useState(true);
  const [currentPage, setCurrentPage] = useState(1);
  const usersPerPage = 6;

  const [editingUser, setEditingUser] = useState(null);
  const role = localStorage.getItem("role");

  /* =========================
     FETCH USERS
  ========================= */
  useEffect(() => {
    fetchUsers();
  }, []);

  const fetchUsers = async () => {
    try {
      const res = await axios.get(BASE_URL);
      setUsers(res.data);
      setFilteredUsers(res.data);
    } catch (err) {
      console.error(err);
      Toast.fire({ icon: "error", title: "Failed to load users" });
    } finally {
      setLoading(false);
    }
  };

  /* =========================
     SEARCH
  ========================= */
  useEffect(() => {
    const filtered = users.filter((u) =>
      (u.name || "").toLowerCase().includes(search.toLowerCase()) ||
      (u.email || "").toLowerCase().includes(search.toLowerCase()) ||
      (u.username || "").toLowerCase().includes(search.toLowerCase())
    );
    setFilteredUsers(filtered);
    setCurrentPage(1);
  }, [search, users]);

  /* =========================
     DELETE USER
  ========================= */
  const deleteUser = async (id) => {
    if (role !== "Admin") {
      Swal.fire("Access Denied", "Only Admin can delete users", "error");
      return;
    }

    const result = await Swal.fire({
      title: "Are you sure?",
      text: "This user will be permanently deleted!",
      icon: "warning",
      showCancelButton: true,
      confirmButtonColor: "#d33",
      cancelButtonColor: "#3085d6",
      confirmButtonText: "Yes, delete it!",
    });

    if (!result.isConfirmed) return;

    try {
      await axios.delete(`${BASE_URL}/${id}`);

      Toast.fire({
        icon: "success",
        title: "User deleted successfully",
      });

      fetchUsers();
    } catch (err) {
      console.error(err);
      Swal.fire("Error", "Failed to delete user", "error");
    }
  };

  /* =========================
     UPDATE USER
  ========================= */
  const updateUser = async () => {
    if (role !== "Admin") {
      Swal.fire("Access Denied", "Only Admin can update users", "error");
      return;
    }

    if (editingUser.role === "Student") {
      Swal.fire("Not Allowed", "Admin cannot update student details", "warning");
      return;
    }

    const result = await Swal.fire({
      title: "Save changes?",
      text: "Do you want to update this user?",
      icon: "question",
      showCancelButton: true,
      confirmButtonColor: "#4f46e5",
      cancelButtonColor: "#6b7280",
      confirmButtonText: "Yes, update",
    });

    if (!result.isConfirmed) return;

    try {
      await axios.put(`${BASE_URL}/${editingUser.id}`, editingUser);

      setEditingUser(null);

      Toast.fire({
        icon: "success",
        title: "User updated successfully",
      });

      fetchUsers();
    } catch (err) {
      console.error(err);
      Swal.fire("Error", "Failed to update user", "error");
    }
  };

  /* =========================
     PAGINATION
  ========================= */
  const indexOfLast = currentPage * usersPerPage;
  const indexOfFirst = indexOfLast - usersPerPage;
  const currentUsers = filteredUsers.slice(indexOfFirst, indexOfLast);
  const totalPages = Math.ceil(filteredUsers.length / usersPerPage);

  const getRoleBadge = (role) => {
    switch (role) {
      case "Admin":
        return "bg-red-500";
      case "Student":
        return "bg-green-500";
      default:
        return "bg-blue-500";
    }
  };

  return (
    <div className="min-h-screen w-[83vw] ml-[17vw] bg-gradient-to-br from-slate-900 via-gray-900 to-slate-800 p-8 text-white">

      {/* HEADER */}
      <div className="flex justify-between items-center mb-8">
        <h1 className="text-3xl font-bold">Admin Dashboard</h1>

        <input
          type="text"
          placeholder="Search users..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="px-4 py-2 rounded-lg text-black w-80 focus:ring-2 focus:ring-indigo-500"
        />
      </div>

      {/* TABLE */}
      {loading ? (
        <p className="text-gray-400">Loading...</p>
      ) : (
        <div className="bg-white/10 backdrop-blur-lg rounded-2xl shadow-xl overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-white/10 text-gray-300">
              <tr>
                <th className="p-4">ID</th>
                <th>Name</th>
                <th>Email</th>
                <th>Username</th>
                <th>Role</th>
                <th>Actions</th>
              </tr>
            </thead>

            <tbody>
              {currentUsers.map((user) => (
                <tr
                  key={user.id}
                  className="border-t border-white/10 hover:bg-white/5 transition"
                >
                  <td className="p-4">{user.id}</td>
                  <td>{user.name}</td>
                  <td>{user.email}</td>
                  <td>{user.username}</td>

                  <td>
                    <span className={`px-3 py-1 text-xs rounded-full text-white ${getRoleBadge(user.role)}`}>
                      {user.role}
                    </span>
                  </td>

                  <td className="flex gap-2 p-2">
                    {role === "Admin" && user.role !== "Student" && (
                      <button
                        onClick={() => setEditingUser(user)}
                        className="px-3 py-1 bg-indigo-600 hover:bg-indigo-700 rounded-lg text-sm transition"
                      >
                        Edit
                      </button>
                    )}

                    {role === "Admin" && (
                      <button
                        onClick={() => deleteUser(user.id)}
                        className="px-3 py-1 bg-red-600 hover:bg-red-700 rounded-lg text-sm transition"
                      >
                        Delete
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* PAGINATION */}
      <div className="flex justify-center mt-6 gap-2">
        {Array.from({ length: totalPages }, (_, i) => (
          <button
            key={i}
            onClick={() => setCurrentPage(i + 1)}
            className={`px-3 py-1 rounded-lg ${
              currentPage === i + 1
                ? "bg-indigo-600"
                : "bg-white/10 hover:bg-white/20"
            }`}
          >
            {i + 1}
          </button>
        ))}
      </div>

      {/* MODAL */}
      {editingUser && (
        <div className="fixed inset-0 flex items-center justify-center bg-black/60 backdrop-blur-sm z-50">

          <div className="relative w-[520px] p-8 rounded-2xl 
            bg-white/10 backdrop-blur-2xl 
            border border-white/20 
            shadow-[0_8px_32px_0_rgba(0,0,0,0.5)]
            overflow-hidden">

            <div className="absolute -top-20 -left-20 w-72 h-72 bg-white/20 rounded-full blur-3xl opacity-30"></div>
            <div className="absolute -bottom-20 -right-20 w-72 h-72 bg-indigo-500/30 rounded-full blur-3xl opacity-30"></div>

            <button
              onClick={() => setEditingUser(null)}
              className="absolute top-3 right-3 text-white hover:text-red-400"
            >
              <XMarkIcon className="w-6 h-6" />
            </button>

            <h2 className="text-xl font-bold mb-6 text-center">Edit User</h2>

            <div className="space-y-4">
              <FloatingLabelInput
                name="name"
                label="Name"
                value={editingUser.name}
                onChange={(e) =>
                  setEditingUser({ ...editingUser, name: e.target.value })
                }
              />

              <FloatingLabelInput
                name="email"
                label="Email"
                value={editingUser.email}
                onChange={(e) =>
                  setEditingUser({ ...editingUser, email: e.target.value })
                }
              />

              <FloatingLabelInput
                name="username"
                label="Username"
                value={editingUser.username}
                onChange={(e) =>
                  setEditingUser({ ...editingUser, username: e.target.value })
                }
              />
            </div>

            <div className="flex justify-end gap-3 mt-6">
              <button
                onClick={updateUser}
                className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 rounded-lg transition"
              >
                Save
              </button>

              <button
                onClick={() => setEditingUser(null)}
                className="px-4 py-2 bg-gray-600 hover:bg-gray-700 rounded-lg transition"
              >
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
